import type { ReactNode } from 'react';
import type { ConvertibleUnit, FormatOptions, Unit } from '@dynatrace-sdk/units';
import type { LabelsDisplay, NameAccessor } from './treemap.js';
import type { TruncationMode } from '../../../typography/text-ellipsis/TextEllipsis.js';
import type { ColorPalette, CustomColorPalette } from '../../core/types/color-palette.js';
import type { ColorRuleProps } from '../../core/types/color-rule.js';
import type { ColoredRange } from '../../core/types/colored-range.js';
import type { Formatter } from '../../core/types/formatter.js';
import type { LegendProps } from '../../core/types/legend.js';
import { ChartToolbarConfig, InternalChartToolbarConfigured } from '../../core/types/toolbar.js';
/**
 * @public
 */
export interface TreeMapContextConfig {
    /**
     * Color palette to use for coloring the tree nodes. Nodes of height 1
     * get a color assigned from the palette. If the are more nodes than
     * colors, they are repeated. Nodes of height 2 get different shades
     * of their parents color assigned. The shading depends on the nodes
     * size compared to the biggest node.
     *
     * @defaultValue 'categorical'
     */
    colorPalette?: ColorPalette | CustomColorPalette | ColoredRange[];
    /**
     * Custom value formatter for the chart.
     */
    formatter?: Formatter | FormatOptions<Unit, ConvertibleUnit>;
    /**
     * The text truncation mode used for the chart legend.
     *
     * @defaultValue 'middle'
     */
    truncationMode?: TruncationMode;
    /**
     * Show the loading indicator.
     *
     * @defaultValue false
     */
    loading?: boolean;
    /**
     * Show/hide label on TreeMap clusters and/or nodes
     */
    labelsDisplay?: LabelsDisplay;
    /**
     * Legend configuration for the treemap chart
     */
    legend?: TreemapChartLegendConfig;
    /**
     * Toolbar configuration for the treemap chart
     */
    toolbar?: TreeMapChartToolbarConfig;
    /**
     * Data accessor on leaf nodes by which legend can be defined
     */
    nameAccessor?: NameAccessor;
    /** The min value configuration to display */
    min?: 'data-min' | number;
    /** The max value configuration to display */
    max?: 'data-max' | number;
    /**
     * Color rules to apply to the treemap nodes
     */
    colorRules?: ColorRuleProps[];
    /**
     * Tooltip configuration for the treemap chart
     */
    tooltip?: TreeMapCustomTooltipConfig;
}
/**
 * @public
 */
export type TreeMapCustomTooltipConfig = {
    hidden?: boolean;
    template?: TreeMapCustomTooltipProps['children'];
};
/**
 * @internal
 */
export type FilteredTreeMapContextConfig = Omit<TreeMapContextConfig, 'toolbar' | 'nameAccessor' | 'min' | 'max' | 'colorRules' | 'tooltip'>;
/**
 * Data passed to a custom TreeMap tooltip render function.
 * @public
 */
export interface TreeMapTooltipPayload {
    /** Node names from root down to the current node (invisible root excluded). */
    hierarchyPath: string[];
    /** Raw numeric value of the node. */
    value: number;
    /** Names of direct child nodes. Undefined for leaf nodes. */
    childrenCount?: string[];
}
/**
 * @public
 */
export interface TreeMapCustomTooltipProps {
    hidden?: boolean;
    symbolAlignment?: 'left' | 'right';
    children?: (payload: TreeMapTooltipPayload) => ReactNode;
}
/**
 * @internal
 */
export type TreeMapConfig = Required<FilteredTreeMapContextConfig> & {
    toolbar?: TreeMapChartToolbarConfig;
    nameAccessor?: NameAccessor;
    min?: 'data-min' | number;
    max?: 'data-max' | number;
    colorRules?: ColorRuleProps[];
    tooltip?: TreeMapCustomTooltipConfig;
};
/**
 * @public
 */
export type TreemapChartLegendConfig = LegendProps;
/**
 * @internal
 */
export interface TreeMapChartSlots {
    legend: Partial<TreemapChartLegendConfig>;
    toolbar: Partial<InternalChartToolbarConfigured> | undefined;
    emptyState?: ReactNode;
    errorState?: ReactNode;
    colorRules?: ColorRuleProps[];
    tooltip?: TreeMapCustomTooltipConfig;
}
/**
 * @public
 */
export type TreeMapChartToolbarConfig = ChartToolbarConfig;
